-- 위험도 공간 확산(Region Risk Spatial Spread) 통합 스키마.
-- 인접 그래프 + 유형별 확산계수(spread_coeff) + region_risk_index source/effective 분리를
-- 한 파일로 통합. (develop 의 기존 V38 과 번호 충돌 회피 목적도 겸함.)


-- 시군구 인접 그래프 (위험도 공간 확산용)
--
-- frontend/public/sigungu.geojson(SIG_CD 5자리) 폴리곤 경계공유로 1회 추출한 불변 참조 데이터.
-- 위험도가 이 그래프를 타고 이웃 시군구로 감쇠 전파된다. region_risk_index 와 FK 안 검 —
-- 인접은 위험도 유무와 무관한 불변 데이터. 섬(육지 경계 0)은 최근접 본토 <=5km 면 다리로 연결,
-- 울릉군(126km)만 고립. 657쌍 × 양방향 = 1314행.

CREATE TABLE region_adjacency (
    region_code   VARCHAR(5) NOT NULL,
    neighbor_code VARCHAR(5) NOT NULL,
    PRIMARY KEY (region_code, neighbor_code)
);



-- 재난 유형별 확산 계수(spread_coeff). 이웃 위험도 = 진원 source × spread_coeff^거리.
-- 기본 0.3 — LLM 생성 신규 유형도 이 값으로 시작.

ALTER TABLE disaster_risk_profile ADD COLUMN spread_coeff DOUBLE PRECISION NOT NULL DEFAULT 0.3;

-- 광역/이동성 재난: 강하게 번짐
UPDATE disaster_risk_profile SET spread_coeff = 0.5 WHERE disaster_type IN ('산불','태풍','황사','미세먼지','원전사고','방사능');
UPDATE disaster_risk_profile SET spread_coeff = 0.4 WHERE disaster_type IN ('호우','대설','폭염','한파','지진해일','감염병','가축질병','적조');
-- 국지/광역 중간
UPDATE disaster_risk_profile SET spread_coeff = 0.3 WHERE disaster_type IN ('지진','강풍','풍랑','해일','화학사고','환경오염');
UPDATE disaster_risk_profile SET spread_coeff = 0.2 WHERE disaster_type IN ('산사태','침수','가스누출','해양사고','기타');
-- 단일 지점 사고: 거의 안 번짐
UPDATE disaster_risk_profile SET spread_coeff = 0.1 WHERE disaster_type IN ('화재','폭발','붕괴','항공사고','철도사고','도로사고','정전','단수','통신장애','민방위');

-- region_risk_index: 자기 위험도(source, 전파 전)와 effective(risk_score, 전파 후) 분리.
-- risk_score 가 FE 노출 최종값으로 의미 전환. source 는 확산 전파의 입력.

ALTER TABLE region_risk_index ADD COLUMN source_score DOUBLE PRECISION NOT NULL DEFAULT 0;
ALTER TABLE region_risk_index ADD COLUMN source_top_event_id BIGINT REFERENCES disaster_events(id);
